-- [ ObfusPro+ ]
local CyAFu = bit32 or bit or error("ObfusPro+: Environment error");
local function JJsCxB(mKPmD)
    local tRdWJZKr = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
    local cWxjx = string.gsub(mKPmD, '[^' .. tRdWJZKr .. ']', '')
    local rStAZJf = {}
    for YyjY = 1, #cWxjx, 4 do
        local KRE, xYE, ZVI, Hyu = string.byte(cWxjx, YyjY, YyjY + 3)
        if not KRE then break end
        local TQdT = string.find(tRdWJZKr, string.char(KRE)) - 1
        local PdHV = string.find(tRdWJZKr, string.char(xYE)) - 1
        local hGND = ZVI and string.find(tRdWJZKr, string.char(ZVI)) - 1 or 0
        local hUsm = Hyu and string.find(tRdWJZKr, string.char(Hyu)) - 1 or 0
        local VRks = TQdT * 262144 + PdHV * 4096 + hGND * 64 + hUsm
        local IbTN = CyAFu.band(CyAFu.rshift(VRks, 16), 255)
        table.insert(rStAZJf, string.char(CyAFu.bxor(IbTN, 117)))
        if ZVI and string.char(ZVI) ~= '=' then
            IbTN = CyAFu.band(CyAFu.rshift(VRks, 8), 255)
            table.insert(rStAZJf, string.char(CyAFu.bxor(IbTN, 117)))
        end
        if Hyu and string.char(Hyu) ~= '=' then
            IbTN = CyAFu.band(VRks, 255)
            table.insert(rStAZJf, string.char(CyAFu.bxor(IbTN, 117)))
        end
    end
    return table.concat(rStAZJf)
end
